import heapq

def minPath(grid, k):
    if k <= 0:
        return []
    rows, cols = len(grid), len(grid[0])
    # start from every cell; push (value, 1, r, c)
    heap = []
    for r in range(rows):
        for c in range(cols):
            heapq.heappush(heap, ([grid[r][c]], 1, r, c))
    visited = set()  # (r, c, steps) to avoid re‑processing same state
    while heap:
        path, steps, r, c = heapq.heappop(heap)
        if steps == k:
            return path
        key = (r, c, steps)
        if key in visited:
            continue
        visited.add(key)
        for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
            nr, nc = r+dr, c+dc
            if 0 <= nr < rows and 0 <= nc < cols:
                new_path = path + [grid[nr][nc]]
                heapq.heappush(heap, (new_path, steps+1, nr, nc))
    # Should never reach here because a path of length k always exists
    raise RuntimeError("Unable to construct path")
```
The heap operations are O(log M) where M is the number of states in the heap (≤ k·rows·cols), giving an overall complexity close to O(k log N²) and dramatically lower memory pressure.

